.app-container {
  max-width: 800px;
  margin: 0 auto;
  padding: 40px 20px;
  display: flex;
  flex-direction: column;
  gap: 30px;
  text-align: left;
}

.app-header {
  border-bottom: 1px solid var(--border);
  padding-bottom: 20px;
}

.app-header h1 {
  margin: 0 0 10px 0;
