.feed-container {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.status-message {
  text-align: center;
  padding: 40px;
  font-size: 1.2rem;
  color: var(--text);
}

.status-message.error {
  color: #ef4444;
